type Heading = "N" | "E" | "S" | "W";

const ROTATIONS: Record<"L" | "R", Record<Heading, Heading>> = {
  L: { N: "W", W: "S", S: "E", E: "N" },
  R: { N: "E", E: "S", S: "W", W: "N" },
};
const FORWARD_DELTA: Record<Heading, [number, number]> = {
  N: [0, 1],
  E: [1, 0],
  S: [0, -1],
  W: [-1, 0],
};

export function execute(commands: string): string {
  let x = 0;
  let y = 0;
  let heading: Heading = "N";
  for (const command of commands) {
    if (command === "L" || command === "R") {
      heading = ROTATIONS[command][heading];
    } else if (command === "F") {
      const [dx, dy] = FORWARD_DELTA[heading];
      x += dx;
      y += dy;
    }
  }
  return `${x}:${y}:${heading}`;
}
